UPDATE t_order
SET pay_order_no = #{payOrderNo}
WHERE user_id = #{userId}
AND order_no IN

    #{orderNo}

mapper.select:
SELECT COUNT(1) AS orderCount,
       COALESCE(SUM(actual_pay_amount), 0) AS salesAmount,
       COUNT(CASE
                 WHEN create_time  >=  #{todayStart}
                  AND create_time  <  #{todayEnd}
                 THEN 1
             END) AS todayOrderCount,
       COALESCE(SUM(CASE
                        WHEN create_time  >=  #{todayStart}
                         AND create_time  <  #{todayEnd}
                        THEN actual_pay_amount
                        ELSE 0
                    END), 0) AS todaySalesAmount,
       COUNT(CASE
                 WHEN create_time  >=  #{last7DaysStart}
                  AND create_time  <  #{todayEnd}
                 THEN 1
             END) AS last7DaysOrderCount,
       COALESCE(SUM(CASE
                        WHEN create_time  >=  #{last7DaysStart}
                         AND create_time  <  #{todayEnd}
                        THEN actual_pay_amount
                        ELSE 0
                    END), 0) AS last7DaysSalesAmount,
       COUNT(CASE
                 WHEN create_time  >=  #{last30DaysStart}
                  AND create_time  <  #{todayEnd}
                 THEN 1
             END) AS last30DaysOrderCount,
       COALESCE(SUM(CASE
                        WHEN create_time  >=  #{last30DaysStart}
                         AND create_time  <  #{todayEnd}
                        THEN actual_pay_amount
                        ELSE 0
                    END), 0) AS last30DaysSalesAmount
FROM t_order
WHERE del_flag = 0
  AND shop_id = #{shopId}
  AND order_status NOT IN

      #{orderStatus}

SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS statDate,
       COUNT(1) AS orderCount,
       COALESCE(SUM(actual_pay_amount), 0) AS salesAmount
FROM t_order
WHERE del_flag = 0
  AND shop_id = #{shopId}
  AND create_time  >=  #{startTime}
  AND create_time  <  #{endTime}
  AND order_status NOT IN

      #{orderStatus}

GROUP BY DATE_FORMAT(create_time, '%Y-%m-%d')
ORDER BY statDate ASC
